const items = $input.all();

const outstanding = [];
const overdue = [];
let totalOutstanding = 0;
let totalOverdue = 0;

for (const item of items) {
  const inv = item.json;
  const contact = inv.Contact?.Name || 'Unknown';
  const amount = inv.AmountDue || 0;
  const ref = inv.InvoiceNumber || inv.Reference || '';
  const due = inv.DueDate ? new Date(inv.DueDate.replace(/\/Date\((\d+)\+.*\)\//, '$1') * 1 || inv.DueDate).toLocaleDateString('en-AU') : 'No date';

  const line = `${contact} — ${ref} — $${amount.toLocaleString('en-AU')} due ${due}`;

  if (inv.Status === 'OVERDUE') {
    overdue.push(line);
    totalOverdue += amount;
  } else {
    outstanding.push(line);
    totalOutstanding += amount;
  }
}

const date = new Date().toLocaleDateString('en-AU', { day: 'numeric', month: 'long', year: 'numeric' });

const lines = [`Xero Financial Summary — ${date}`, ''];

if (overdue.length) {
  lines.push(`OVERDUE (${overdue.length} invoices, total $${totalOverdue.toLocaleString('en-AU')})`);
  overdue.forEach(l => lines.push(`  • ${l}`));
  lines.push('');
}

if (outstanding.length) {
  lines.push(`OUTSTANDING (${outstanding.length} invoices, total $${totalOutstanding.toLocaleString('en-AU')})`);
  outstanding.forEach(l => lines.push(`  • ${l}`));
}

if (!overdue.length && !outstanding.length) {
  lines.push('No outstanding or overdue invoices.');
}

return [{ json: { content: lines.join('\n') } }];
